import{_ as a,o as i,c as s,ai as e}from"./chunks/framework.BIXs0jTs.js";const n="/assets/preface-cover.Balx8Fq4.png",u=JSON.parse('{"title":"团队级 Skill 体系","description":"","frontmatter":{"title":"团队级 Skill 体系"},"headers":[],"relativePath":"20-skill/team-system.md","filePath":"20-skill/team-system.md","lastUpdated":null}'),o={name:"20-skill/team-system.md"};function t(r,l,p,c,d,h){return i(),s("div",null,[...l[0]||(l[0]=[e('<h1 id="第-7-章-团队级-skill-体系-共享与协作" tabindex="-1">第 7 章　团队级 Skill 体系：共享与协作 <a class="header-anchor" href="#第-7-章-团队级-skill-体系-共享与协作" aria-label="Permalink to &quot;第 7 章　团队级 Skill 体系：共享与协作&quot;">​</a></h1><p><img src="'+n+`" alt="团队级 Skill 体系：共享与协作"></p><p>如果说个人 Skill 是开发者的“私人瑞士军刀”，那么团队级 Skill 体系就是整个组织的“中央军火库”。</p><p>当一个团队有 10 人、50 人甚至 100 人在使用 Claude Code 时，我们面临的挑战就不再是如何写好一个 Prompt，而是：</p><ul><li>如何让新人一入职就拥有资深员工积累的 Skill？</li><li>如何防止每个人都写一遍 <code>generate_sql</code>，导致出现 10 个不同版本？</li><li>如何统一管理和更新这些 Skill？</li></ul><p>本章将探讨如何构建一个<strong>可扩展、可维护的团队级 Skill 体系</strong>。</p><h2 id="_7-1-从-我的-skill-到-我们的-skill" tabindex="-1">7.1 从“我的 Skill”到“我们的 Skill” <a class="header-anchor" href="#_7-1-从-我的-skill-到-我们的-skill" aria-label="Permalink to &quot;7.1 从“我的 Skill”到“我们的 Skill”&quot;">​</a></h2><h3 id="_7-1-1-孤岛现象" tabindex="-1">7.1.1 孤岛现象 <a class="header-anchor" href="#_7-1-1-孤岛现象" aria-label="Permalink to &quot;7.1.1 孤岛现象&quot;">​</a></h3><p>在没有统一管理的情况下，很容易出现“Prompt 孤岛”：</p><ul><li>Alice 写了一个很棒的 <code>review_pr</code> Skill，但只有她自己知道。</li><li>Bob 刚入职，不知道怎么用 Claude 写单测，自己瞎琢磨了一套效果很差的 Prompt。</li><li>Charlie 发现 Alice 的 Skill 有个 Bug，修复了但没告诉 Alice。</li></ul><h3 id="_7-1-2-共享的价值" tabindex="-1">7.1.2 共享的价值 <a class="header-anchor" href="#_7-1-2-共享的价值" aria-label="Permalink to &quot;7.1.2 共享的价值&quot;">​</a></h3><p>建立团队级 Skill 库的核心价值在于：</p><ol><li><strong>能力复用</strong>：一次编写，全员受益。</li><li><strong>规范落地</strong>：通过 Skill 强制推行代码规范（如 Commit 格式、命名风格）。</li><li><strong>知识沉淀</strong>：将团队的最佳实践固化为可执行的代码（Skill），而不是躺在 Wiki 里的死文档。</li></ol><hr><h2 id="_7-2-管理-skill-仓库-gitops" tabindex="-1">7.2 管理 Skill 仓库 (GitOps) <a class="header-anchor" href="#_7-2-管理-skill-仓库-gitops" aria-label="Permalink to &quot;7.2 管理 Skill 仓库 (GitOps)&quot;">​</a></h2><p>最简单的管理方式是使用 Git 仓库。</p><h3 id="_7-2-1-仓库结构推荐" tabindex="-1">7.2.1 仓库结构推荐 <a class="header-anchor" href="#_7-2-1-仓库结构推荐" aria-label="Permalink to &quot;7.2.1 仓库结构推荐&quot;">​</a></h3><p>建议创建一个名为 <code>claude-skills</code> 或 <code>engineering-prompts</code> 的独立仓库。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>claude-skills/</span></span>
<span class="line"><span>├── README.md           # 索引与安装指南</span></span>
<span class="line"><span>├── skills/             # 核心 Skill 目录</span></span>
<span class="line"><span>│   ├── git/</span></span>
<span class="line"><span>│   │   ├── commit-msg.json</span></span>
<span class="line"><span>│   │   └── pr-desc.json</span></span>
<span class="line"><span>│   ├── code/</span></span>
<span class="line"><span>│   │   ├── refactor.json</span></span>
<span class="line"><span>│   │   └── unit-test.json</span></span>
<span class="line"><span>│   └── ops/</span></span>
<span class="line"><span>│       └── k8s-logs.json</span></span>
<span class="line"><span>├── configs/            # 推荐的 .clauderc 配置</span></span>
<span class="line"><span>│   └── recommended.json</span></span>
<span class="line"><span>└── docs/               # 开发文档</span></span></code></pre></div><h3 id="_7-2-2-分发机制" tabindex="-1">7.2.2 分发机制 <a class="header-anchor" href="#_7-2-2-分发机制" aria-label="Permalink to &quot;7.2.2 分发机制&quot;">​</a></h3><p>如何让每个人的 Claude Code 都能加载这些 Skill？</p><p><strong>方案 A：Git Submodule / Clone（推荐）</strong> 每个开发者在本地机器上 clone 这个仓库，并在自己的 Claude Code 配置中指向该目录。</p><p><strong>方案 B：MCP 服务分发</strong> 建立一个内部的 MCP Server，专门负责通过网络下发 Skill。当 Skill 更新时，服务端更新即可，客户端无感知。这是更高级的玩法（将在第 III 部分详细介绍）。</p><hr><h2 id="_7-3-版本控制与发布" tabindex="-1">7.3 版本控制与发布 <a class="header-anchor" href="#_7-3-版本控制与发布" aria-label="Permalink to &quot;7.3 版本控制与发布&quot;">​</a></h2><p>Skill 也是代码，应该遵循软件工程的版本管理原则。</p><h3 id="_7-3-1-语义化版本" tabindex="-1">7.3.1 语义化版本 <a class="header-anchor" href="#_7-3-1-语义化版本" aria-label="Permalink to &quot;7.3.1 语义化版本&quot;">​</a></h3><p>给 Skill 库打 Tag，例如 <code>v1.0.0</code>。</p><ul><li><strong>Major</strong>：Prompt 逻辑大改，接口不兼容（参数变了）。</li><li><strong>Minor</strong>：增加了新 Skill，或优化了现有 Skill 的效果。</li><li><strong>Patch</strong>：修复了 Prompt 中的错别字或微调语气。</li></ul><h3 id="_7-3-2-变更日志-changelog" tabindex="-1">7.3.2 变更日志 (Changelog) <a class="header-anchor" href="#_7-3-2-变更日志-changelog" aria-label="Permalink to &quot;7.3.2 变更日志 (Changelog)&quot;">​</a></h3><p>在 <code>CHANGELOG.md</code> 中记录：</p><blockquote><p><strong>v1.2.0</strong></p><ul><li>新增 <code>java_doc_gen</code> Skill。</li><li>优化 <code>commit_msg</code>：现在支持 Emoji 前缀了。</li><li>修复 <code>sql_query</code> 在多表 Join 时的幻觉问题。</li></ul></blockquote><hr><h2 id="_7-4-治理-谁来批准一个-skill" tabindex="-1">7.4 治理：谁来批准一个 Skill？ <a class="header-anchor" href="#_7-4-治理-谁来批准一个-skill" aria-label="Permalink to &quot;7.4 治理：谁来批准一个 Skill？&quot;">​</a></h2><p>不要让 Skill 库变成垃圾场。需要引入 <strong>Skill Review</strong> 机制。</p><h3 id="_7-4-1-提交标准" tabindex="-1">7.4.1 提交标准 <a class="header-anchor" href="#_7-4-1-提交标准" aria-label="Permalink to &quot;7.4.1 提交标准&quot;">​</a></h3><p>提交一个新的 Skill 到团队库时，必须包含：</p><ol><li><strong>接口定义</strong>：清晰的输入输出描述。</li><li><strong>测试用例</strong>：至少 3 个“输入-输出”样本，证明它是有效的。</li><li><strong>适用范围</strong>：说明在什么情况下使用（如“仅适用于 Python 项目”）。</li></ol><h3 id="_7-4-2-维护者-maintainers" tabindex="-1">7.4.2 维护者 (Maintainers) <a class="header-anchor" href="#_7-4-2-维护者-maintainers" aria-label="Permalink to &quot;7.4.2 维护者 (Maintainers)&quot;">​</a></h3><p>指定 1-2 位“AI 效能工程师”或资深开发者作为维护者。他们的职责是：</p><ul><li>Review 同事提交的 Skill PR。</li><li>定期清理过时或低频使用的 Skill。</li><li>监控 Skill 的使用效果（通过收集反馈）。</li></ul><h3 id="_7-4-3-风格指南" tabindex="-1">7.4.3 风格指南 <a class="header-anchor" href="#_7-4-3-风格指南" aria-label="Permalink to &quot;7.4.3 风格指南&quot;">​</a></h3><p>制定一份《Prompt 编写指南》，统一团队的 Prompt 风格：</p><ul><li>统一称呼（如“你是一个资深工程师”）。</li><li>统一输出格式（如“优先使用 Markdown 表格”）。</li><li>统一语言（中文/英文）。</li></ul><hr><h2 id="_7-5-小结" tabindex="-1">7.5 小结 <a class="header-anchor" href="#_7-5-小结" aria-label="Permalink to &quot;7.5 小结&quot;">​</a></h2><p>团队级 Skill 体系的建设，标志着一个团队从“尝鲜 AI”走向了“AI 工程化”。</p><ul><li>用 <strong>Git 仓库</strong> 统一管理 Skill。</li><li>用 <strong>版本控制</strong> 追踪变更。</li><li>用 <strong>Review 机制</strong> 保证质量。</li></ul><p>当你的团队拥有了一套成熟的 Skill 体系，新入职的员工只需 <code>git clone</code> 一下，就能立刻获得全团队积累多年的智慧加持。这就是 AI 时代的“站在巨人的肩膀上”。</p><p>至此，我们已经完成了关于 Skill 的全部内容。在接下来的<strong>第 III 部分</strong>，我们将跨越 Claude Code 的边界，通过 <strong>MCP (Model Context Protocol)</strong> 去连接更广阔的外部世界——数据库、Jira、Slack 以及生产环境。</p>`,50)])])}const g=a(o,[["render",t]]);export{u as __pageData,g as default};
